   159|export async function executeSupabaseSqlScript(
   160|  client: SupabaseClient,
   161|  sql: string,
   162|  onProgress?: (progress: SupabaseSqlProgress) => void,
   163|): Promise<{ totalStatements: number }> {
   164|  const statements = splitSupabaseSqlStatements(sql);
   165|
