cd /home/user/rork-app && node -e '
const fs = require("fs");
const path = require("path");
const root = "logs/audit/task-orchestrator";
const blocked = [];
for (const dir of fs.readdirSync(root)) {
  if (!dir.startsWith("task-")) continue;
  const file = path.join(root, dir, "task.json");
  if (!fs.existsSync(file)) continue;
  const task = JSON.parse(fs.readFileSync(file, "utf8"));
  if (task.status === "blocked") blocked.push({ dir, file, task });
}
blocked.sort((a, b) => (a.task.createdAt || "").localeCompare(b.task.createdAt || ""));
console.log("blocked tasks:", blocked.length);
const keeper = blocked[blocked.length - 1];
const now = new Date().toISOString();
const reviewer = "IVX IA Senior Developer (owner execution order 2026-07-11)";

for (const { dir, file, task } of blocked) {
  const isKeeper = dir === keeper.dir;
  const disposition = isKeeper ? "blocked_owner_approval" : "cancelled_obsolete";
  const classification = isKeeper ? "REQUIRES_OWNER_APPROVAL" : "CANCELLED_OBSOLETE";
  task.status = disposition;
  task.updatedAt = now;
  task.disposition = {
    classification,
    reviewedAt: now,
    reviewedBy: reviewer,
    action: "Step 2 of this task chain orders: Delete all user data from the production database",
    affectedResource: "Supabase production database: members, profiles, auth.users, wallets, transactions (all user rows)",
    recordsAffected: "ALL user records — irreversible mass deletion",
    destructive: true,
    backupExists: false,
    rollbackPossible: false,
    safeSubSteps: "Steps 1 (refactor header) and 3 (update footer) are chained behind the destructive step and were intentionally not auto-executed without a real owner specification",
    recommendation: isKeeper
      ? "HOLD for explicit owner approval. Mass user-data deletion is never auto-executed. Approve or reject via owner command."
      : "Cancelled as an exact duplicate of the retained approval request " + keeper.task.id + " (same command, later run kept).",
    duplicateOf: isKeeper ? null : keeper.task.id,
  };
  fs.writeFileSync(file, JSON.stringify(task, null, 2));

  const eventsFile = path.join(root, dir, "events.jsonl");
  const event = {
    type: isKeeper ? "TASK_BLOCKED_OWNER_APPROVAL" : "TASK_CANCELLED_OBSOLETE",
    at: now,
    taskId: task.id,
    reviewedBy: reviewer,
    classification,
    reason: isKeeper
      ? "Destructive step (delete ALL production user data) requires explicit owner approval; no backup exists and rollback is impossible. Safe sub-steps held with it pending a real specification."
      : "Exact duplicate of retained owner-approval request " + keeper.task.id + " (identical command; this earlier run adds no new work).",
    evidence: {
      command: (task.ownerCommand || "").slice(0, 200),
      destructiveStep: "2. Delete all user data from the production database",
      duplicateOf: isKeeper ? null : keeper.task.id,
      reviewOrder: "FINAL EXECUTION ORDER 2026-07-11 sections 14-16",
    },
  };
  fs.appendFileSync(eventsFile, JSON.stringify(event) + "\n");
  console.log(dir.slice(0, 46), "->", disposition);
}
console.log("KEEPER=" + keeper.task.id);
'

